import { Camera } from '@capacitor/camera';
import { Filesystem, Directory } from '@capacitor/filesystem';
import { Preferences } from '@capacitor/preferences';

const PHOTO_INDEX_KEY = 'photo_index';

async function getIndex(): Promise<string[]> {
  const { value } = await Preferences.get({ key: PHOTO_INDEX_KEY });
  if (value === null) {
    return [];
  }
  try {
    return JSON.parse(value) as string[];
  } catch {
    return [];
  }
}

async function saveIndex(index: string[]): Promise<void> {
  await Preferences.set({ key: PHOTO_INDEX_KEY, value: JSON.stringify(index) });
}

export async function capturePhoto(): Promise<string> {
  // Camera.takePhoto is available since @capacitor/camera 8.1.0
  // On Web, result.thumbnail contains the full image as a base64 string
  const result = await Camera.takePhoto({
    saveToGallery: false,
    includeMetadata: true,
  });

  // On Web, thumbnail holds the full image base64-encoded (no data URI prefix)
  const base64Data = result.thumbnail ?? '';

  const timestamp = new Date().toISOString();
  const path = `photos/${timestamp}.jpeg`;

  await Filesystem.writeFile({
    path,
    data: base64Data,
    directory: Directory.Data,
    recursive: true,
  });

  const index = await getIndex();
  index.push(path);
  await saveIndex(index);

  return path;
}

export async function listPhotos(): Promise<string[]> {
  return getIndex();
}

export async function deletePhoto(path: string): Promise<void> {
  try {
    await Filesystem.deleteFile({
      path,
      directory: Directory.Data,
    });
  } catch {
    // File may not exist; still update the index
  }

  const index = await getIndex();
  const updated = index.filter((p) => p !== path);
  await saveIndex(updated);
}

import { capturePhoto, listPhotos, deletePhoto } from './gallery';

// Expose gallery API on window so automated tests can invoke it
declare global {
  interface Window {
    gallery: {
      capturePhoto: () => Promise<string>;
      listPhotos: () => Promise<string[]>;
      deletePhoto: (path: string) => Promise<void>;
    };
  }
}

window.gallery = {
  capturePhoto,
  listPhotos,
  deletePhoto,
};

// Render the UI
const app = document.getElementById('app');
if (app) {
  app.innerHTML = `
    <h1>Photo Gallery</h1>
    <button id="capture-btn" type="button">Capture Photo</button>
    <p id="capture-status">idle</p>
    <ul id="photo-list"></ul>
  `;

  const captureBtn = document.getElementById('capture-btn') as HTMLButtonElement;
  const captureStatus = document.getElementById('capture-status') as HTMLParagraphElement;

  captureBtn.addEventListener('click', async () => {
    captureStatus.textContent = 'capturing';
    try {
      const path = await capturePhoto();
      captureStatus.textContent = 'saved';
      console.log('Photo saved at:', path);
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      captureStatus.textContent = `error: ${message}`;
      console.error('Capture failed:', err);
    }
  });
}
